changeSet.sql:
CREATE TABLE IF NOT EXISTS bookings ( id VARCHAR(36) PRIMARY KEY, user_id VARCHAR(36) NOT NULL, specialist_id VARCHAR(36) NOT NULL, service_id VARCHAR(36) NOT NULL, start_time TIMESTAMP NOT NULL, status VARCHAR(20) NOT NULL, created_at TIMESTAMP NOT NULL,
CONSTRAINT fk_bookings_user FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
CONSTRAINT fk_bookings_specialist_profile FOREIGN KEY (specialist_id) REFERENCES specialist_profile(id) ON DELETE CASCADE,
CONSTRAINT fk_bookings_specialist_service FOREIGN KEY (service_id) REFERENCES specialist_service(id) ON DELETE CASCADE );
CREATE INDEX IF NOT EXISTS idx_bookings_user_id ON bookings (user_id);
CREATE INDEX IF NOT EXISTS idx_bookings_specialist_id ON bookings (specialist_id);
CREATE INDEX IF NOT EXISTS idx_bookings_start_time ON bookings (start_time);
